    .witch-item {
      background: rgba(34, 6, 48, 0.15);
      border: 1px solid rgba(239, 155, 89, 0.4);
      border-radius: 12px;
      padding: 10px 15px;
      display: flex;
      align-items: center;
      gap: 10px;
      position: relative;
    }

    .witch-label {
      font-weight: bold;
