    /* 气泡提示 */
    .bubble-tip {
      position: absolute;
      bottom: calc(100% + 15px);
      right: 0;
      background: var(--witch-yellow);
      color: var(--witch-dark);
      padding: 4px 10px;
      border-radius: 6px;
      font-size: 12px;
      font-weight: bold;
