      border-right: 6px solid transparent;
    }
    .witch-progress-box:focus .bubble-tip { opacity: 1; transform: scale(1) translateY(0); }

    /* 子折叠区域 */
    .sub-section { border-top: 1px solid rgba(136, 93, 157, 0.3); margin-top: 10px; }
    .sub-summary {
      list-style: none;
      cursor: pointer;
      color: var(--witch-orange);
      padding: 15px 10px;
      display: flex;
      align-items: center;
      gap: 10px;
      font-weight: bold;
    }
    .sub-summary::before {
      content: '';
      width: 20px; height: 20px;
      background: url('https://testingcf.jsdelivr.net/gh/kayanorin/SillyTavernimg/nl39g8.png') no-repeat center/contain;
      transition: transform 0.3s;
    }
