  } else {
    console.warn('无法注册MESSAGE_SWIPED事件监听器，但自动监控仍可正常工作');
  }

  // 启动自动监控
  startSwipeMonitor();

  // 初始化时获取当前状态
  setTimeout(async () => {
    await safeMonitorSwipeChanges();
    isInitialized = true;
  }, 1000); // 延迟1秒执行，确保应用已完全加载
}

// 在脚本卸载时执行
function onScriptUnload() {
  console.log('Swipe切换时控制世界书条目脚本已卸载。');
  toastr.info('开场白自动切换脚本已停用。');

  // 停止监控器
